import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface RetentionData {
  day: number;
  percentage: number;
}

interface EngagementMetrics {
  dauMauRatio: number;
  averageSessionDuration: string;
  retentionCurve: RetentionData[];
}

export default function Widget() {
  const { engagementMetrics } = response.data as { engagementMetrics: EngagementMetrics };
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: theme === 'dark' ? '#2E3B4E' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              DAU/MAU Ratio
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: primaryColor }}>
              {(engagementMetrics.dauMauRatio * 100).toFixed(2)}%
            </Typography>
          </Box>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Avg. Session Duration
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: accentColor }}>
              {engagementMetrics.averageSessionDuration}
            </Typography>
          </Box>
          <Box sx={{ width: '100%', height: 150 }}>
            <LineChart
              height={150}
              series={[
                {
                  data: engagementMetrics.retentionCurve.map(point => point.percentage),
                  color: primaryColor,
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: engagementMetrics.retentionCurve.map(point => `Day ${point.day}`),
                  scaleType: 'band',
                  tickLabelStyle: { fontSize: 10, fill: theme === 'dark' ? '#FFFFFF' : '#000000' },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
